import useRestoreSession from "@adapters/hooks/useLoadUser";
import ErrorBoundary from "@infrastructure/errorBoundary";
import { LocaleProvider } from "@infrastructure/i18n/LocaleProvider";
import ToastConfig from "@infrastructure/toast.config";
import { OfflineIndicator } from "@presentation/components/offline-indicator";
import RouteConfig from "@presentation/routes/route-config";

function App() {
  useRestoreSession();
  return (
    <div className="App">
      <OfflineIndicator />
      <ErrorBoundary>
        <LocaleProvider>
          <RouteConfig />
        </LocaleProvider>
      </ErrorBoundary>
      <ToastConfig />
    </div>
  );
}

export default App;

import {
  createContext,
  useContext,
  useState,
  useEffect,
  type ReactNode,
} from "react";
import { useMobile } from "./useMobile";

interface SidebarContextType {
  isOpen: boolean;
  isCollapsed: boolean;
  toggleSidebar: () => void;
  closeSidebar: () => void;
}

const SidebarContext = createContext<SidebarContextType | undefined>(undefined);

export function SidebarProvider({ children }: { children: ReactNode }) {
  const [isOpen, setIsOpen] = useState(true);
  const [isCollapsed, setIsCollapsed] = useState(false);
  const isMobile = useMobile();

  // Update sidebar state based on screen size
  useEffect(() => {
    if (isMobile) {
      setIsOpen(false);
      setIsCollapsed(false);
    } else {
      setIsOpen(true);
    }
  }, [isMobile]);

  const toggleSidebar = () => {
    if (isMobile) {
      setIsOpen(!isOpen);
    } else {
      setIsCollapsed(!isCollapsed);
    }
  };

  const closeSidebar = () => {
    if (isMobile) {
      setIsOpen(false);
    }
  };

  return (
    <SidebarContext.Provider
      value={{ isOpen, isCollapsed, toggleSidebar, closeSidebar }}
    >
      {children}
    </SidebarContext.Provider>
  );
}

// eslint-disable-next-line react-refresh/only-export-components
export function useSidebar() {
  const context = useContext(SidebarContext);
  if (context === undefined) {
    throw new Error("useSidebar must be used within a SidebarProvider");
  }
  return context;
}

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "light" | "dark";

const ThemeContext = createContext<
  { theme: Theme; toggleTheme: () => void } | undefined
>(undefined);

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const storedTheme = localStorage.getItem("theme") as Theme | null;
  const [theme, setTheme] = useState<Theme>(storedTheme || "light");

  const toggleTheme = () => {
    const newTheme = theme === "light" ? "dark" : "light";
    setTheme(newTheme);
    localStorage.setItem("theme", newTheme);
  };

  useEffect(() => {
    if (storedTheme) {
      document.querySelector("body")?.setAttribute("data-theme", storedTheme);
    }
  }, [storedTheme]);

  useEffect(() => {
    const root = document.querySelector("body") as HTMLElement;

    // Remover transiciones iniciales
    root.classList.remove("transition-all", "duration-500");

    if (theme === "dark") {
      root.classList.add("dark");
    } else {
      root.classList.remove("dark");
    }

    // Añadir transiciones después del cambio inicial
    setTimeout(() => {
      root.classList.add("transition-all", "duration-500");
    }, 10);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

// eslint-disable-next-line react-refresh/only-export-components
export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
};

import { logoutAction } from "@adapters/slices/auth/authSlice";
import { store } from "@adapters/store/rootStore";
import { AuthRepository } from "@domain/auth/AuthRepository";
import { User } from "@domain/index";
import api from "@infrastructure/api.config";
import { getAuth, GoogleAuthProvider, signInWithPopup } from "firebase/auth";

export const authRepository: AuthRepository = {
  async login(email: string, password: string) {
    try {
      const response = await api.post("/auth/login", { email, password });

      return response.data;
    } catch (error: any) {
      console.error("Error:", error.message);
      throw error;
    }
  },

  async logout() {
    await api.post("/auth/logout");
    store.dispatch(logoutAction());
    window.location.href = "/login";
  },

  async signup(user: Omit<User, "id">) {
    const response = await api.post("/auth/signup", user);
    return response.data;
  },

  async forgotPassword(email: string) {
    const response = await api.post("/auth/forgot-password", { email });
    return response.data;
  },

  async resetPassword(newPassword: string, token: string) {
    const response = await api.post("/auth/reset-password", {
      newPassword,
      token,
    });
    return response.data;
  },

  async refreshToken(refreshToken: string) {
    const response = await api.post("/auth/refresh", { refreshToken });
    return response.data;
  },

  async googleLogin() {
    const auth = getAuth();
    const provider = new GoogleAuthProvider();

    try {
      const result = await signInWithPopup(auth, provider);
      const user = result.user;
      const idToken = await user.getIdToken(); // Token JWT de Firebase

      const response = await api.post("/auth/firebase-login", { idToken });

      return response.data;
    } catch (error) {
      console.error("Error during Google login:", error);
      throw error;
    }
  },

  async googleAuthRedirect(code: string) {
    return await api.get("/auth/google-callback", { params: { code } });
    // return response.data;
  },

  async githubLogin() {
    const response = await api.get("/auth/github-login");
    return response.data;
  },
};

