import { useFetchBudgets } from "@adapters/query/dashboard";
import { RootState } from "@adapters/store/rootStore";
import { OverBudgetIcon } from "@presentation/components/ui/budget-status";
import getColorBasedOnEndDate from "@presentation/utils/colorGeneratorBasedOnDate";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import { RoutePaths } from "@presentation/utils/routes";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";
import { Link } from "react-router";
import Loader from "../loader";

export function BudgetProgress() {
  const { t } = useTranslation();
  const { data: budgets, isLoading, isSuccess } = useFetchBudgets();
  const userSetting = useSelector((state: RootState) => state.userSettings);

  const { settings } = userSetting;

  const displayedBudgets = budgets?.slice(-1 * 3) || [];
  const hasOverBudget = displayedBudgets.some(
    (b) => b.totalSpent > b.totalAllocated,
  );

  return (
    <div
      className={`rounded-lg p-6 shadow-sm transition-colors ${
        hasOverBudget
          ? "border border-red-300 bg-red-50/80 dark:border-red-800 dark:bg-red-950/30"
          : "bg-white dark:bg-slate-800"
      }`}
    >
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <OverBudgetIcon isOverBudget={hasOverBudget} size="md" />
          <h2 className="text-lg font-semibold">
            {t("dashboard.budgetProgress")}
          </h2>
        </div>
        <Link
          to={RoutePaths.App + "/" + RoutePaths.Budgets}
          className="text-sm text-purple-600 hover:underline dark:text-purple-400"
        >
          {t("dashboard.manageBudgets")}
        </Link>
      </div>
      <div className="space-y-4">
        {isLoading && <Loader />}
        {isSuccess && budgets?.length > 0 ? (
          budgets?.slice(-1 * 3)?.map((budget) => {
            const percentage = Math.min(
              Math.round((budget.totalSpent / budget.totalAllocated) * 100),
              100,
            );
            const isOverBudget = budget.totalSpent > budget.totalAllocated;

            const targetCurrency = (settings?.currency || "USD") as Currency;

            const formattedSpent = currencyService.formatCurrency(
              budget.totalSpent,
              "USD" as Currency,
              targetCurrency,
              false,
            );

            const formattedAllocated = currencyService.formatCurrency(
              budget.totalAllocated,
              "USD" as Currency,
              targetCurrency,
              false,
            );

            return (
              <div key={budget.id}>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-sm font-medium">{budget.name}</span>
                  <span className="text-sm text-slate-500 dark:text-slate-400">
                    {formattedSpent.formatted} / {formattedAllocated.formatted}
                  </span>
                </div>
                <div className="h-2 w-full rounded-full bg-slate-100 dark:bg-slate-700">
                  <div
                    className={`h-2 rounded-full progress-shim ${
                      isOverBudget
                        ? "bg-red-500"
                        : getColorBasedOnEndDate(budget.endDate)
                    }`}
                    style={{ width: `${percentage}%` }}
                  ></div>
                </div>
                <div className="mt-1 flex justify-between text-xs">
                  <span
                    className={
                      isOverBudget
                        ? "text-red-500 dark:text-red-400"
                        : "text-slate-500 dark:text-slate-400"
                    }
                  >
                    {percentage}% {isOverBudget && t("dashboard.overBudget")}
                  </span>
                  <span className="text-slate-500 dark:text-slate-400">
                    {Math.max(
                      formattedAllocated.amount - formattedSpent.amount,
                      0,
                    )}{" "}
                    {t("dashboard.left")}
                  </span>
                </div>
              </div>
            );
          })
        ) : (
          <div className="flex items-center justify-center">
            <span className="text-muted-foreground">
              {t("dashboard.noBudgetsYet")}
            </span>
          </div>
        )}
      </div>
    </div>
  );
}

import { RootState } from "@adapters/store/rootStore";
import { TRANSACTION_CATEGORIES } from "@domain/dashboard/transactions/transaction.entity";
import { Button } from "@presentation/components/ui/button";
import { Input } from "@presentation/components/ui/input";
import { Label } from "@presentation/components/ui/label";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";

export default function AddBudgetCategory({
  name,
  allocated,
  spent,
  handleNewCategoryChange,
  handleAddCategorySubmit,
}: {
  name: string;
  allocated: string;
  spent: string;
  handleNewCategoryChange: (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>,
  ) => void;
  handleAddCategorySubmit: () => void;
}) {
  const { t } = useTranslation();
  const userSetting = useSelector((state: RootState) => state.userSettings);
  const targetCurrency = (userSetting?.settings?.currency || "USD") as Currency;
  const currencySymbol = currencyService.getSymbol(targetCurrency);

  return (
    <div className="rounded-lg border border-slate-200 p-4 dark:border-slate-700">
      <div className="flex items-end gap-2">
        <div className="flex-1 space-y-2">
          <Label htmlFor="new-category-name">{t("budgets.categoryName")}</Label>
          <select
            id={`category-name-${name}`}
            name="name"
            value={name}
            onChange={handleNewCategoryChange}
            className="w-full rounded-md border border-slate-200 bg-white px-3 py-2 text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500 dark:border-slate-700 dark:bg-slate-800 dark:text-white"
            required
          >
            <option value="">{t("transactions.selectCategory")}</option>
            {TRANSACTION_CATEGORIES.map((category) => (
              <option key={category} value={category}>
                {t(`categories.${category.toLowerCase()}`)}
              </option>
            ))}
          </select>
        </div>
        <div className="flex-1 space-y-2">
          <Label htmlFor="new-category-allocated">
            {t("budgets.allocatedAmount")}
          </Label>
          <div className="relative">
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
              {currencySymbol}
            </span>
            <Input
              id="new-category-allocated"
              type="number"
              name="allocated"
              min="0"
              step="0.01"
              value={allocated}
              onChange={handleNewCategoryChange}
              className="pl-7"
              required
            />
          </div>
        </div>
        <div className="flex-1 space-y-2">
          <Label htmlFor="new-category-spent">{t("budgets.spentAmount")}</Label>
          <div className="relative">
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
              {currencySymbol}
            </span>
            <Input
              id="new-category-spent"
              type="number"
              name="spent"
              min="0"
              step="0.01"
              value={spent}
              onChange={handleNewCategoryChange}
              className="pl-7"
              required
            />
          </div>
        </div>
        <Button onClick={handleAddCategorySubmit}>{t("common.add")}</Button>
      </div>
    </div>
  );
}

import { RootState } from "@adapters/store/rootStore";
import { BudgetCategory } from "@domain/dashboard/budgets/budget.entity";
import { Button } from "@presentation/components/ui/button";
import { Input } from "@presentation/components/ui/input";
import { Label } from "@presentation/components/ui/label";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import { useState } from "react";
import { useSelector } from "react-redux";

interface Props {
  category: BudgetCategory;
  onUpdateSpent: (categoryId: number, spent: number) => void;
  onDeleteCategory: (category: BudgetCategory) => void;
}

export const EditableBudgetCategory: React.FC<Props> = ({
  category,
  onUpdateSpent,
  onDeleteCategory,
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localSpent, setLocalSpent] = useState(category.spent);

  const userSetting = useSelector((state: RootState) => state.userSettings);

  const { settings } = userSetting;

  const handleEditClick = () => {
    setIsEditing(true);
  };

  const handleCancelClick = () => {
    setIsEditing(false);
    setLocalSpent(category.spent);
  };

  const handleSaveClick = () => {
    if (!category) return;
    onUpdateSpent(category.id as number, localSpent);
    setIsEditing(false);
  };

  const handleLocalSpentChange = (value: string) => {
    const spent = Number(value) || 0;
    setLocalSpent(spent);
  };

  const targetCurrency = (settings?.currency || "USD") as Currency;

  const formattedSpent = currencyService.formatCurrency(
    category.spent,
    "USD" as Currency,
    targetCurrency,
    false,
  );

  return (
    <div className="mt-3 flex items-center justify-between">
      <div className="flex-1">
        <Label htmlFor={`category-spent-${category.id}`} className="text-xs">
          {isEditing ? "Update Spent Amount" : "Spent"}
        </Label>
        <div className="relative mt-1">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
            {formattedSpent.symbol}
          </span>
          {isEditing ? (
            <Input
              id={`category-spent-${category.id}`}
              type="number"
              min="0"
              step="0.01"
              value={localSpent}
              onChange={(e) => handleLocalSpentChange(e.target.value)}
              className="pl-7"
            />
          ) : (
            <span className="pl-7">{formattedSpent.amount}</span>
          )}
        </div>
      </div>
      <div className="flex items-center">
        {!isEditing ? (
          <Button
            variant="default"
            size="sm"
            className="ml-2"
            onClick={handleEditClick}
          >
            Edit
          </Button>
        ) : (
          <>
            <Button
              variant="outline"
              size="sm"
              className="ml-2"
              onClick={handleSaveClick}
            >
              Save
            </Button>
            <Button
              variant="ghost"
              size="sm"
              className="ml-2"
              onClick={handleCancelClick}
            >
              Cancel
            </Button>
          </>
        )}
        <Button
          variant="ghost"
          size="sm"
          className="ml-2 text-red-500 hover:bg-red-50 hover:text-red-600 dark:hover:bg-red-900/20"
          onClick={(e) => {
            e.stopPropagation();
            onDeleteCategory(category);
          }}
        >
          Delete
        </Button>
      </div>
    </div>
  );
};

