import { HttpBudgetRepository } from "@adapters/http/budget.repository";
import { useFetchBudgetCategories } from "@adapters/query/dashboard";
import { RootState } from "@adapters/store/rootStore";
import {
  Budget,
  BudgetCategory,
} from "@domain/dashboard/budgets/budget.entity";
import Loader from "@presentation/components/loader";
import { Button } from "@presentation/components/ui/button";
import {
  successToast,
  errorToast,
  warningToast,
  infoToast,
} from "@presentation/utils/toast";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Plus } from "lucide-react";
import { useState, useMemo, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import AddBudgetCategory from "./add-budget-category";
import BudgetHeader from "./budget-header";
import BudgetSpendingByCategory from "./budget-spending-ny-cat";
import BudgetSummary from "./budget-summary";
import BudgetCategoryList from "./category-list";

interface BudgetDetailProps {
  onEditBudget: (budget: Budget) => void;
  selectedBudget?: Budget;
  isRefreshed?: boolean;
  refetchBudgets?: () => void;
}

export function BudgetDetail({
  onEditBudget,
  selectedBudget,
  isRefreshed,
  refetchBudgets,
}: BudgetDetailProps) {
  const { t } = useTranslation();
  const user = useSelector((state: RootState) => state.auth.user);
  const userSettings = useSelector((state: RootState) => state.userSettings);

  const queryClient = useQueryClient();

  const activeBudget = selectedBudget?.id;

  const [newCategory, setNewCategory] = useState<BudgetCategory>({
    budgetId: 0,
    name: "",
    allocated: undefined as unknown as number,
    spent: undefined as unknown as number,
  });
  const [isAddingCategory, setIsAddingCategory] = useState(false);

  const {
    data: categoryBudgets,
    isLoading,
    refetch: refetchCategories,
  } = useFetchBudgetCategories({ budgetId: Number(activeBudget), name: "" });

  // Mutations invalidate the above query so list auto‑refreshes
  const invalidate = useCallback(() => {
    queryClient.invalidateQueries({
      queryKey: ["budgetCategories", activeBudget],
    });
    queryClient.invalidateQueries({ queryKey: ["dashboard"] });
  }, [queryClient, activeBudget]);

  // Funciones de mutación optimizadas con useCallback
  const handleAddCategorySuccess = useCallback(() => {
    successToast(
      "Budget category added successfully",
      3000,
      "budget-category-add",
    );
    setNewCategory({
      budgetId: activeBudget ?? 0,
      name: "",
      allocated: undefined as unknown as number,
      spent: undefined as unknown as number,
    });
    invalidate();
    refetchBudgets?.();
    refetchCategories();
  }, [activeBudget, invalidate, refetchBudgets, refetchCategories]);

  const handleMutationErrorDetailed = useCallback(
    (error: any, operation: string) => {
      const message =
        error?.response?.data?.message ||
        error?.message ||
        `Failed to ${operation} budget category`;
      const errorMsg = Array.isArray(message) ? message[0] : message;
      errorToast(errorMsg, 5000, `budget-category-${operation}`);
    },
    [],
  );

  const { mutate: addBudgetCategory } = useMutation({
    mutationKey: ["add-budget-category"],
    mutationFn: HttpBudgetRepository.createBudgetCategory,
    onSuccess: handleAddCategorySuccess,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onError: (error: any) => handleMutationErrorDetailed(error, "add"),
    onSettled: () => {
      refetchBudgets?.();
      refetchCategories();
    },
  });

  const { mutate: updateBudgetCategory } = useMutation({
    mutationKey: ["update-budget-category"],
    mutationFn: HttpBudgetRepository.updateBudgetCategory,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onSuccess: (_data: any) => {
      successToast(
        "Budget category updated successfully",
        3000,
        "budget-category-update",
      );
      invalidate();
    },
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onError: (error: any) => handleMutationErrorDetailed(error, "update"),
    onSettled: () => {
      refetchBudgets?.();
      refetchCategories();
    },
  });

  const { mutate: deleteBudgetCategory } = useMutation({
    mutationKey: ["delete-budget-category"],
    mutationFn: HttpBudgetRepository.deleteBudgetCategory,
    onSuccess: () => {
      successToast(
        "Budget category deleted successfully",
        3000,
        "budget-category-delete",
      );
      invalidate();
    },
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onError: (error: any) => handleMutationErrorDetailed(error, "delete"),
    onSettled: () => {
      refetchBudgets?.();
      refetchCategories();
    },
  });

  // Summary and chart data
  const totalAllocated = selectedBudget?.totalAllocated ?? 0;
  const totalSpent = selectedBudget?.totalSpent ?? 0;
  const remaining = totalAllocated - totalSpent;
  const percentSpent =
    totalAllocated > 0 ? (totalSpent / totalAllocated) * 100 : 0;

  const chartData = useMemo(
    () =>
      categoryBudgets?.map((c) => ({
        name: c.name,
        allocated: c.allocated,
        spent: c.spent,
        percentUsed: c.allocated > 0 ? (c.spent / c.allocated) * 100 : 0,
      })) || [],
    [categoryBudgets],
  );

  // Handlers optimizados con useCallback
  const onUpdateSpent = useCallback(
    (categoryId: number, spent: number) => {
      // Normalize from display currency to USD before saving
      const targetCurrency = (userSettings?.settings?.currency ||
        "USD") as Currency;
      const normalizedSpent = currencyService.normalizeAmount(
        spent,
        targetCurrency,
      );

      // Check if new spent exceeds allocated & show friendly warning
      const category = categoryBudgets?.find((c) => c.id === categoryId);
      if (category && normalizedSpent > category.allocated) {
        const overAmount = normalizedSpent - category.allocated;
        warningToast(
          t("budgets.overBudgetCategory", {
            category: category.name,
            amount: overAmount.toFixed(2),
          }),
          5000,
          "budget-over",
        );
      } else if (
        category &&
        normalizedSpent >= 0 &&
        normalizedSpent <= category.allocated
      ) {
        infoToast(t("budgets.budgetHealthy"), 3000, "budget-healthy");
      }
      updateBudgetCategory({ id: categoryId, spent: normalizedSpent });
    },
    [updateBudgetCategory, categoryBudgets, t, userSettings],
  );

  const handleAddCategoryClick = useCallback(() => {
    setIsAddingCategory((prevState) => !prevState);
  }, []);

  const handleNewCategoryChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setNewCategory((prev) => ({
        ...prev,
        [name]:
          name === "allocated" || name === "spent"
            ? value === ""
              ? (undefined as unknown as number)
              : Number(value) || 0
            : value,
      }));
    },
    [],
  );

  const handleAddCategorySubmit = useCallback(() => {
    if (!user || !activeBudget) return;

    if (newCategory.name.trim() === "" || !newCategory.allocated) return;

    const targetCurrency = (userSettings?.settings?.currency ||
      "USD") as Currency;

    addBudgetCategory({
      ...newCategory,
      budgetId: activeBudget,
      allocated: currencyService.normalizeAmount(
        Number(newCategory.allocated) || 0,
        targetCurrency,
      ),
      spent: currencyService.normalizeAmount(
        Number(newCategory.spent) || 0,
        targetCurrency,
      ),
    });
  }, [user, activeBudget, newCategory, addBudgetCategory, userSettings]);

  const onDeleteCategoryHandler = useCallback(
    (categoryToDelete: BudgetCategory) => {
      deleteBudgetCategory(categoryToDelete.id as number);
    },
    [deleteBudgetCategory],
  );

  const handleEditBudgetClick = useCallback(() => {
    if (activeBudget && selectedBudget) {
      onEditBudget(selectedBudget);
    }
  }, [activeBudget, onEditBudget, selectedBudget]);

  // Render condicional del loader más legible
  if (isRefreshed || isLoading) {
    return <Loader />;
  }

  if (!activeBudget) {
    return (
      <div className="md:mt-11 rounded-lg border border-dashed bg-purple-50 p-6 text-center dark:border-purple-900/30 dark:bg-purple-900/20 md:p-10 lg:p-16 xl:p-20 border-slate-200 dark:border-slate-700">
        <p className="text-slate-500 dark:text-slate-400">
          {t("common.selectBudget")}
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Budget Header */}
      <BudgetHeader
        name={selectedBudget?.name ?? ""}
        startDate={selectedBudget?.startDate ?? new Date()}
        endDate={selectedBudget?.endDate ?? new Date()}
        period={selectedBudget?.period ?? ""}
        handleEditBudgetClick={handleEditBudgetClick}
      />

      {/* Budget Summary */}
      <BudgetSummary
        totalAllocated={selectedBudget?.totalAllocated ?? 0}
        totalSpent={selectedBudget?.totalSpent ?? 0}
        remaining={remaining}
        percentSpent={percentSpent}
      />

      {/* spending by category */}
      <BudgetSpendingByCategory chartData={chartData} />

      {/* budget categories */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-medium">
            {t("common.budgetCategories")}
          </h3>
          <Button
            variant="outline"
            size="sm"
            className="gap-1"
            onClick={handleAddCategoryClick}
          >
            <Plus className="h-4 w-4" />
            {t("budgets.addCategory")}
          </Button>
        </div>

        {isAddingCategory && (
          <AddBudgetCategory
            name={newCategory.name}
            allocated={newCategory.allocated?.toString() ?? ""}
            spent={newCategory.spent?.toString() ?? ""}
            handleNewCategoryChange={handleNewCategoryChange}
            handleAddCategorySubmit={handleAddCategorySubmit}
          />
        )}

        {/* list of categories */}
        {categoryBudgets && categoryBudgets?.length > 0 ? (
          <BudgetCategoryList
            categoryBudgets={categoryBudgets}
            onUpdateSpent={onUpdateSpent}
            onDeleteCategoryHandler={onDeleteCategoryHandler}
          />
        ) : (
          <div className="rounded-lg border border-dashed border-slate-200 p-6 text-center dark:border-slate-700">
            <p className="text-slate-500 dark:text-slate-400">
              {t("budgets.noCategoriesYet")}
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

import { RootState } from "@adapters/store/rootStore";
import {
  Budget,
  BudgetCategory,
  PERIOD_OPTIONS,
} from "@domain/dashboard/budgets/budget.entity";
import { TRANSACTION_CATEGORIES } from "@domain/dashboard/transactions/transaction.entity";
import { Button } from "@presentation/components/ui/button";
import { Input } from "@presentation/components/ui/input";
import { Label } from "@presentation/components/ui/label";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import { Trash2 } from "lucide-react";
import { useState, useEffect, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";

interface BudgetFormProps {
  budget?: Budget;
  onSubmit: (budget: Partial<Budget>) => void;
  onCancel: () => void;
  isLoading?: boolean;
}

type CategoryInputRefs = {
  [key: string]: {
    // Key será `${index}-${fieldName}`
    current: HTMLInputElement | HTMLSelectElement | null;
  };
};

export function BudgetForm({ budget, onSubmit, onCancel }: BudgetFormProps) {
  const { t } = useTranslation();
  const userSetting = useSelector((state: RootState) => state.userSettings);
  const targetCurrency = (userSetting?.settings?.currency || "USD") as Currency;
  const currencySymbol = currencyService.getSymbol(targetCurrency);

  const [formData, setFormData] = useState<Partial<Budget>>({
    name: "",
    period: "Monthly",
    startDate: new Date(new Date().setMonth(new Date().getMonth())),
    endDate: new Date(new Date().setMonth(new Date().getMonth() + 1)),
    totalAllocated: 0,
    totalSpent: 0,
  });

  const [categories, setCategories] = useState<BudgetCategory[]>([]);
  const categoryInputRefs = useRef<CategoryInputRefs>({});

  const totalAllocated = categories.reduce(
    (sum, category) => sum + category.allocated,
    0,
  );
  const totalSpent = categories.reduce(
    (sum, category) => sum + category.spent,
    0,
  );

  useEffect(() => {
    if (budget) {
      setFormData({
        ...budget,
        startDate: new Date(budget.startDate),
        endDate: new Date(budget.endDate),
      });
      setCategories(budget.categories);
    } else {
      const today = new Date();
      const firstDay = new Date(today.getFullYear(), today.getMonth(), 1);
      const lastDay = new Date(today.getFullYear(), today.getMonth() + 1, 0);
      setFormData({
        name: "Monthly Budget",
        period: PERIOD_OPTIONS[0],
        startDate: firstDay,
        endDate: lastDay,
        totalAllocated: 0,
        totalSpent: 0,
      });
      setCategories([
        {
          budgetId: 0,
          name: "",
          allocated: undefined as unknown as number,
          spent: undefined as unknown as number,
        },
      ]);
    }
  }, [budget]);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>,
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleCategoryInputChange = (
    index: number,
    field: keyof BudgetCategory,
    value: string | number,
  ) => {
    setCategories((prev) => {
      const updated = [...prev];
      const currentValue =
        typeof value === "string" &&
        (field === "allocated" || field === "spent")
          ? value === ""
            ? (undefined as unknown as number)
            : Number(value) || 0
          : value;
      updated[index] = { ...updated[index], [field]: currentValue };
      return updated;
    });
  };

  const addCategory = () => {
    setCategories((prev) => [
      ...prev,
      {
        budgetId: budget?.id ?? 0,
        name: "",
        allocated: undefined as unknown as number,
        spent: undefined as unknown as number,
      },
    ]);
  };

  const removeCategory = (index: number) => {
    setCategories((prev) => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const normalizedCategories = categories.map((cat) => ({
      ...cat,
      allocated: currencyService.normalizeAmount(
        Number(cat.allocated) || 0,
        targetCurrency,
      ),
      spent: currencyService.normalizeAmount(
        Number(cat.spent) || 0,
        targetCurrency,
      ),
    }));
    onSubmit({ ...formData, categories: normalizedCategories });
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="space-y-6 overflow-y-auto max-h-[80vh]"
    >
      <div className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="name">{t("budgets.budgetName")}</Label>

          <Input
            id="name"
            name="name"
            value={formData.name}
            onChange={handleChange}
            placeholder={t("budgets.namePlaceholder")}
            required
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="period">{t("budgets.budgetPeriod")}</Label>

          <select
            id="period"
            name="period"
            value={formData.period}
            onChange={handleChange}
            className="w-full rounded-md border border-slate-200 bg-white px-3 py-2 text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500 dark:border-slate-700 dark:bg-slate-800 dark:text-white"
            required
          >
            {PERIOD_OPTIONS.map((period) => (
              <option key={period} value={period}>
                {t(
                  `periods.${
                    period === "Bi-weekly"
                      ? "biWeekly"
                      : period === "One-time"
                      ? "oneTime"
                      : period.toLowerCase()
                  }`,
                )}
              </option>
            ))}
          </select>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label htmlFor="startDate">{t("budgets.startDate")}</Label>

            <Input
              id="startDate"
              name="startDate"
              type="date"
              value={
                formData.startDate instanceof Date
                  ? formData.startDate.toISOString().split("T")[0]
                  : formData.startDate
              }
              onChange={handleChange}
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="endDate">{t("budgets.endDate")}</Label>

            <Input
              id="endDate"
              name="endDate"
              type="date"
              value={
                formData.endDate instanceof Date
                  ? formData.endDate.toISOString().split("T")[0]
                  : formData.endDate
              }
              onChange={handleChange}
              required
            />
          </div>
        </div>
      </div>
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-medium">
            {t("budgets.budgetCategories")}
          </h3>
          <Button
            type="button"
            variant="outline"
            size="sm"
            onClick={addCategory}
            disabled={!!budget}
          >
            {t("budgets.addCategory")}
          </Button>
        </div>

        <div className="space-y-4">
          {categories.map((category, index) => (
            <div key={index} className="flex items-end gap-2">
              <div className="flex-1 space-y-2">
                <Label htmlFor={`category-name-${index}`}>
                  {t("budgets.categoryName")}
                </Label>
                <select
                  id={`category-name-${index}`}
                  value={category.name}
                  onChange={(e) =>
                    handleCategoryInputChange(index, "name", e.target.value)
                  }
                  className="w-full rounded-md border border-slate-200 bg-white px-3 py-2 text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500 dark:border-slate-700 dark:bg-slate-800 dark:text-white"
                  ref={(el) => {
                    if (el) {
                      categoryInputRefs.current[`${index}-name`] = {
                        current: el,
                      };
                    }
                  }}
                  required
                >
                  {TRANSACTION_CATEGORIES.map((cat) => (
                    <option key={cat} value={cat}>
                      {t(`categories.${cat.toLowerCase()}`)}
                    </option>
                  ))}
                </select>
              </div>
              <div className="flex-1 space-y-2">
                <Label htmlFor={`category-allocated-${index}`}>
                  {t("budgets.allocatedAmount")}
                </Label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
                    {currencySymbol}
                  </span>
                  <Input
                    id={`category-allocated-${index}`}
                    type="number"
                    min="0"
                    step="0.01"
                    value={category.allocated ?? ""}
                    onChange={(e) =>
                      handleCategoryInputChange(
                        index,
                        "allocated",
                        e.target.value,
                      )
                    }
                    className="pl-7"
                    ref={(el) => {
                      if (categoryInputRefs.current[`${index}-allocated`]) {
                        categoryInputRefs.current[
                          `${index}-allocated`
                        ].current = el;
                      } else {
                        categoryInputRefs.current[`${index}-allocated`] = {
                          current: el,
                        };
                      }
                    }}
                    required
                  />
                </div>
              </div>
              <div className="flex-1 space-y-2">
                <Label htmlFor={`category-spent-${index}`}>
                  {t("budgets.spentAmount")}
                </Label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
                    {currencySymbol}
                  </span>
                  <Input
                    id={`category-spent-${index}`}
                    type="number"
                    min="0"
                    step="0.01"
                    value={category.spent ?? ""}
                    onChange={(e) =>
                      handleCategoryInputChange(index, "spent", e.target.value)
                    }
                    className="pl-7"
                    ref={(el) => {
                      if (categoryInputRefs.current[`${index}-spent`]) {
                        categoryInputRefs.current[`${index}-spent`].current =
                          el;
                      } else {
                        categoryInputRefs.current[`${index}-spent`] = {
                          current: el,
                        };
                      }
                    }}
                    required
                  />
                </div>
              </div>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                onClick={() => removeCategory(index)}
                className="mb-0.5 text-red-500 hover:bg-red-50 hover:text-red-600 dark:hover:bg-red-900/20"
              >
                <Trash2 className="h-4 w-4" />
              </Button>
            </div>
          ))}
        </div>

        <div className="rounded-lg border border-slate-200 p-4 dark:border-slate-700">
          <div className="flex items-center justify-between">
            <span className="font-medium">{t("budgets.totalBudget")}</span>
            <span className="text-lg font-bold">
              {currencySymbol}
              {(totalAllocated - totalSpent).toFixed(2)}
            </span>
          </div>
        </div>
      </div>

      <div className="flex justify-end gap-2">
        <Button type="button" variant="outline" onClick={onCancel}>
          {t("common.cancel")}
        </Button>
        <Button type="submit">
          {budget ? t("budgets.submitUpdate") : t("budgets.submitCreate")}
        </Button>
      </div>
    </form>
  );
}

import { Button } from "@presentation/components/ui/button";
import { CalendarIcon, Edit2 } from "lucide-react";

export default function BudgetHeader({
  name,
  startDate,
  endDate,
  period,
  handleEditBudgetClick,
}: {
  name: string;
  startDate: Date;
  endDate: Date;
  period: string;
  handleEditBudgetClick: () => void;
}) {
  return (
    <div className="flex items-center justify-between">
      <div>
        <h2 className="text-xl font-semibold">{name}</h2>
        <div className="mt-1 flex items-center gap-1 text-sm text-slate-500 dark:text-slate-400">
          <CalendarIcon className="h-4 w-4" />
          <span>
            {new Date(startDate).toLocaleDateString()} -{" "}
            {new Date(endDate).toLocaleDateString()}
          </span>
          <span className="ml-2 rounded-md bg-slate-100 px-2 py-0.5 text-xs dark:bg-slate-700">
            {period}
          </span>
        </div>
      </div>
      <Button
        variant="outline"
        size="sm"
        className="gap-1"
        onClick={handleEditBudgetClick}
      >
        <Edit2 className="h-4 w-4" />
        Edit Budget
      </Button>
    </div>
  );
}

import { RootState } from "@adapters/store/rootStore";
import { Budget } from "@domain/dashboard/budgets/budget.entity";
import Loader from "@presentation/components/loader";
import { OverBudgetIcon } from "@presentation/components/ui/budget-status";
import { Button } from "@presentation/components/ui/button";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import { CalendarIcon, Pencil, Trash2 } from "lucide-react";
import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";

interface BudgetListProps {
  budgets: Budget[];
  isLoading: boolean;
  onBudgetSelect: (budget: Budget) => void;
  onEditBudget: (budget: Budget) => void;
  onDeleteBudget: (budgetId: string | number) => void;
}

export function BudgetList({
  onBudgetSelect,
  onEditBudget,
  onDeleteBudget,
  budgets,
  isLoading,
}: BudgetListProps) {
  const { t } = useTranslation();
  const [activeBudget, setActiveBudget] = useState<Budget | null>(null);

  const userSetting = useSelector((state: RootState) => state.userSettings);

  const { settings } = userSetting;

  const handleSelectBudget = (budget: Budget) => {
    setActiveBudget(budget);
    onBudgetSelect(budget);
  };

  return (
    <div className="space-y-4">
      <h2 className="text-lg font-semibold">{t("common.yourBudgets")}</h2>

      {isLoading && <Loader />}

      {budgets && budgets.length > 0 ? (
        <div className="space-y-2">
          {budgets.map((budget) => {
            const isActive = activeBudget?.id === budget.id;
            const percentSpent =
              budget.totalAllocated > 0
                ? (budget.totalSpent / budget.totalAllocated) * 100
                : 0;
            const remaining = budget.totalAllocated - budget.totalSpent;

            const formattedRemaining = currencyService.formatCurrency(
              remaining,
              settings?.currency as Currency,
              settings?.currency as Currency,
            );

            const targetCurrency = (settings?.currency || "USD") as Currency;
            const formattedAllocated = currencyService.formatCurrency(
              budget.totalAllocated,
              targetCurrency as Currency,
              targetCurrency,
            );

            const formattedSpent = currencyService.formatCurrency(
              budget.totalSpent,
              targetCurrency as Currency,
              targetCurrency,
            );

            // Determine progress color based on percentage spent
            let progressColor = "bg-green-500";
            if (percentSpent > 90) {
              progressColor = "bg-red-500";
            } else if (percentSpent > 75) {
              progressColor = "bg-yellow-500";
            }

            const isOverBudget = budget.totalSpent > budget.totalAllocated;
            const isActiveBudget = activeBudget?.id === budget.id;

            let borderClasses =
              "border-slate-200 bg-white hover:border-purple-200 dark:border-slate-700 dark:bg-slate-800 dark:hover:border-purple-700";
            if (isActiveBudget) {
              borderClasses =
                "border-purple-500 bg-purple-50 dark:border-purple-500 dark:bg-purple-900/20";
            }
            if (isOverBudget) {
              borderClasses =
                "border-red-300 bg-red-50/80 dark:border-red-800 dark:bg-red-950/40";
              if (isActiveBudget) {
                borderClasses =
                  "border-red-400 bg-red-50 dark:border-red-500 dark:bg-red-950/60 ring-1 ring-red-400/50";
              }
            }

            return (
              <div
                key={budget.id}
                className={`rounded-lg border p-4 transition-colors cursor-pointer ${borderClasses}`}
                onClick={() => handleSelectBudget(budget)}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <OverBudgetIcon isOverBudget={isOverBudget} size="sm" />
                    <h3 className="font-medium">{budget.name}</h3>
                  </div>
                  <div className="flex items-center gap-1">
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8"
                      onClick={(e) => {
                        e.stopPropagation();
                        onEditBudget(budget);
                      }}
                    >
                      <Pencil className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8 text-red-500 hover:bg-red-50 hover:text-red-600 dark:hover:bg-red-900/20"
                      onClick={(e) => {
                        e.stopPropagation();
                        onDeleteBudget(budget.id);
                      }}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>

                <div className="mt-2 flex items-center gap-1 text-xs text-slate-500 dark:text-slate-400">
                  <CalendarIcon className="h-3 w-3" />
                  <span>
                    {new Date(budget.startDate).toLocaleDateString()} -{" "}
                    {new Date(budget.endDate).toLocaleDateString()}
                  </span>
                </div>

                <div className="mt-4">
                  <div className="flex items-center justify-between text-sm">
                    <span>
                      ${formattedSpent.formatted.split("+")[1]} of $
                      {formattedAllocated.formatted.split("+")[1]}
                    </span>
                    <span className="font-medium">
                      {Math.round(percentSpent)}%
                    </span>
                  </div>
                  <div className="mt-1 h-2 w-full rounded-full bg-slate-100 dark:bg-slate-700">
                    <div
                      className={`h-2 rounded-full ${progressColor}`}
                      style={{ width: `${Math.min(percentSpent, 100)}%` }}
                    ></div>
                  </div>
                </div>

                <div className="mt-2 text-sm">
                  <span
                    className={
                      remaining >= 0
                        ? "text-green-600 dark:text-green-400"
                        : "text-red-600 dark:text-red-400"
                    }
                  >
                    {remaining >= 0
                      ? `${formattedRemaining.formatted.split("+")[1]} ${t(
                          "budgets.remaining",
                        )}`
                      : `${Math.abs(formattedRemaining.amount).toFixed(2)} ${t(
                          "dashboard.overBudget",
                        )}`}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="rounded-lg border border-dashed bg-purple-50 p-6 text-center dark:border-purple-900/30 dark:bg-purple-900/20 md:p-10 md:text-left lg:p-16 xl:p-20 border-slate-200 dark:border-slate-700">
          <p className="text-slate-500 dark:text-slate-400">
            {t("budgets.noBudgetsFound")}
          </p>
        </div>
      )}
    </div>
  );
}

import { HttpBudgetRepository } from "@adapters/http/budget.repository";
import { Budget } from "@domain/dashboard/budgets/budget.entity";
import { Modal } from "@presentation/components/modal/modal";
import { successToast, errorToast } from "@presentation/utils/toast";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { BudgetForm } from "./budget-form";

interface BudgetModalProps {
  isOpen: boolean;
  onClose: () => void;
  budget?: Budget;
  refetchBudgets?: () => void;
}

export function BudgetModal({
  isOpen,
  onClose,
  budget,
  refetchBudgets,
}: BudgetModalProps) {
  const { t } = useTranslation();
  const isEditing = !!budget;

  const queryClient = useQueryClient();

  const { mutate: addBudget } = useMutation({
    mutationKey: ["add-budget"],
    mutationFn: HttpBudgetRepository.createBudget,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onSuccess: (data: any) => {
      successToast(
        data?._offline ? data.message : t("budgets.createSuccess"),
        3000,
        "budget-create",
      );
      queryClient.invalidateQueries({ queryKey: ["budgets"] });
      queryClient.invalidateQueries({ queryKey: ["dashboard"] });
      if (!data?._offline) {
        refetchBudgets?.();
      }
      onClose();
    },
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onError: (error: any) => {
      const message =
        error?.response?.data?.message ||
        error?.message ||
        t("budgets.createError");
      const errorMsg = Array.isArray(message) ? message[0] : message;
      errorToast(errorMsg, 5000, "budget-create");
      console.error("Budget creation failed:", error);
      queryClient.invalidateQueries({ queryKey: ["budgets"] });
    },
  });

  const { mutate: updateBudget } = useMutation({
    mutationKey: ["update-budget"],
    mutationFn: HttpBudgetRepository.updateBudget,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onSuccess: (data: any) => {
      successToast(
        data?._offline ? data.message : t("budgets.updateSuccess"),
        3000,
        "budget-update",
      );
      queryClient.invalidateQueries({ queryKey: ["budgets"] });
      queryClient.invalidateQueries({ queryKey: ["dashboard"] });
      if (!data?._offline) {
        refetchBudgets?.();
      }
      onClose();
    },
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onError: (error: any) => {
      const message =
        error?.response?.data?.message ||
        error?.message ||
        t("budgets.updateError");
      const errorMsg = Array.isArray(message) ? message[0] : message;
      errorToast(errorMsg, 5000, "budget-update");
      console.error("Budget update failed:", error);
      queryClient.invalidateQueries({ queryKey: ["budgets"] });
    },
  });

  const handleSubmit = (budgetData: Partial<Budget>) => {
    if (isEditing && budget) {
      updateBudget({
        ...budgetData,
        id: budget.id,
      });
    } else {
      addBudget(budgetData);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={isEditing ? t("budgets.editBudget") : t("budgets.createBudget")}
    >
      <BudgetForm budget={budget} onSubmit={handleSubmit} onCancel={onClose} />
    </Modal>
  );
}

import {
  OverBudgetContainer,
  OverBudgetHeader,
  OverBudgetBadge,
} from "@presentation/components/ui/budget-status";
import {
  ResponsiveContainer,
  CartesianGrid,
  XAxis,
  YAxis,
  Tooltip,
  Bar,
  Cell,
  BarChart,
} from "recharts";

interface ChartEntry {
  name: string;
  allocated: number;
  spent: number;
  percentUsed: number;
}

export default function BudgetSpendingByCategory({
  chartData,
}: {
  chartData: ChartEntry[];
}) {
  const hasOverBudget = chartData.some((d) => d.percentUsed > 100);
  const overBudgetCount = chartData.filter((d) => d.percentUsed > 100).length;

  return (
    <OverBudgetContainer isOverBudget={hasOverBudget}>
      <OverBudgetHeader
        isOverBudget={hasOverBudget}
        title="Spending by Category"
        iconSize="md"
        badge={
          hasOverBudget
            ? `${overBudgetCount} ${
                overBudgetCount === 1 ? "category over" : "categories over"
              } budget`
            : undefined
        }
      />

      {/* Chart */}
      <div className="h-64">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart
            data={chartData}
            layout="vertical"
            margin={{ top: 5, right: 30, left: 40, bottom: 5 }}
          >
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis type="number" />
            <YAxis dataKey="name" type="category" width={100} />
            <Tooltip
              content={({ active, payload, label }) => {
                if (!active || !payload?.length) return null;
                const entry = chartData.find((d) => d.name === label);
                if (!entry) return null;
                const isOver = entry.percentUsed > 100;
                const overAmount = entry.spent - entry.allocated;

                return (
                  <div className="rounded-lg border bg-white p-3 shadow-lg dark:border-slate-700 dark:bg-slate-800">
                    <p className="mb-1 font-medium">{label}</p>
                    {payload.map((p, i) => (
                      <p key={i} className="text-sm">
                        <span className="font-medium">{p.name}:</span> $
                        {Number(p.value).toFixed(2)}
                      </p>
                    ))}
                    {isOver && (
                      <p className="mt-1 text-sm font-medium text-red-600 dark:text-red-400">
                        ⚠ Over budget by ${overAmount.toFixed(2)}
                      </p>
                    )}
                  </div>
                );
              }}
            />
            <Bar dataKey="allocated" name="Allocated" fill="#8884d8" />
            <Bar dataKey="spent" name="Spent" fill="#82ca9d">
              {chartData.map((entry, index) => (
                <Cell
                  key={`cell-${index}`}
                  fill={
                    entry.percentUsed > 100
                      ? "#ef4444"
                      : entry.percentUsed > 90
                      ? "#f59e0b"
                      : "#10b981"
                  }
                />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </OverBudgetContainer>
  );
}

