              <LineChart data={overview?.monthly || []}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip
                  formatter={(value) => [formatCurrency(Number(value)), ""]}
                />
                <Legend />
                <Line
                  type="monotone"
                  dataKey="expenses"
                  name={t("reports.totalExpenses")}
                  stroke="#ef4444"
                  activeDot={{ r: 8 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </ChartContainer>

          <ChartContainer title={t("reports.weeklyPattern")}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={weeklyTrend}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="day" />
                <YAxis />
                <Tooltip
                  formatter={(value) => [formatCurrency(Number(value)), ""]}
                />
                <Bar
                  dataKey="amount"
                  name={t("reports.spendingLabel")}
                  fill="#8b5cf6"
                />
              </BarChart>
            </ResponsiveContainer>
          </ChartContainer>
        </div>
      )}
      {insights && (
        <div className="rounded-lg bg-white p-6 shadow-sm dark:bg-slate-800">
          <h3 className="mb-4 text-lg font-medium">
            {t("reports.trendAnalysis")}
          </h3>
          <div className="grid gap-4 md:grid-cols-3">
            <InsightBox
              title={t("reports.projectedNextMonth")}
              value={formatCurrency(insights.projectedExpenses)}
