          <nav
            className={`mt-2 flex-1 space-y-1 ${isCollapsed ? "px-1" : "px-2"}`}
          >
            {navigation.map((item) => {
              const isActive = pathname === item.href;
              const label = t("sidebar." + item.key);
              return (
                <Link
                  key={item.key}
                  to={item.href}
                  className={getLinkClasses(item, isActive)}
                  title={isCollapsed ? label : ""}
                >
