import { HttpTransactionRepository } from "@adapters/http/transaction.repository";
import { Transaction } from "@domain/dashboard/transactions/transaction.entity";
import { Modal } from "@presentation/components/modal/modal";
import { Button } from "@presentation/components/ui/button";
import { successToast, errorToast } from "@presentation/utils/toast";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Plus } from "lucide-react";
import { useState } from "react";
import { useTranslation } from "react-i18next";
import AddTransactionForm from "./add-transaction";

export function AddTransactionModal({ isHeader }: { isHeader?: boolean }) {
  const { t } = useTranslation();
  const [isOpen, setIsOpen] = useState(false);

  const queryClient = useQueryClient();

  const { mutate: addTransaction } = useMutation({
    mutationKey: ["add-transaction"],
    mutationFn: HttpTransactionRepository.createTransaction,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onSuccess: (data: any) => {
      successToast(data.message, 3000, "transaction-create");
      queryClient.invalidateQueries({ queryKey: ["transactions"] });
      queryClient.invalidateQueries({ queryKey: ["dashboard"] });
      setIsOpen(false);
    },
    onError: (error) => {
      errorToast(error.message, 3000, "transaction-create");
    },
  });

  const handleAddTransaction = (transaction: Omit<Transaction, "id">) => {
    if (transaction.amount === 0) {
      errorToast("Amount cannot be 0", 3000, "invalid-amount");
      return;
    }

    addTransaction({
      dto: {
        ...transaction,
      },
    });
  };

  return (
    <>
      {!isHeader ? (
        <>
          <Button
            variant="primary"
            onClick={() => setIsOpen(true)}
            size="lg"
            className="inline-flex items-center gap-2 px-6 py-2.5 text-base font-semibold shadow-md hover:shadow-lg transition-all"
          >
            <Plus className="h-5 w-5" />
            {t("transactions.addTransaction")}
          </Button>

          <Modal isOpen={isOpen} onClose={() => setIsOpen(false)} title="">
            <AddTransactionForm
              onSubmit={handleAddTransaction}
              onCancel={() => setIsOpen(false)}
            />
          </Modal>
        </>
      ) : (
        <>
          <Button
            variant="primary"
            onClick={() => setIsOpen(true)}
            size="icon"
            className="rounded-full bg-purple-50 p-1 text-purple-600 hover:text-purple-700 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:ring-offset-2 dark:bg-slate-800 dark:text-purple-400 dark:hover:text-purple-300"
          >
            <Plus className="h-4 w-4" />
          </Button>
          <Modal
            isOpen={isOpen}
            onClose={() => setIsOpen(false)}
            title={t("transactions.addNewTransaction")}
          >
            <AddTransactionForm
              onSubmit={handleAddTransaction}
              onCancel={() => setIsOpen(false)}
            />
          </Modal>
        </>
      )}
    </>
  );
}

import { RootState } from "@adapters/store/rootStore";
import {
  TRANSACTION_CATEGORIES,
  Transaction,
} from "@domain/dashboard/transactions/transaction.entity";
import { Button } from "@presentation/components/ui/button";
import { Input } from "@presentation/components/ui/input";
import { Label } from "@presentation/components/ui/label";
import { Currency, currencyService } from "@presentation/utils/currencyService";
import { errorToast } from "@presentation/utils/toast";
import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";

interface AddTransactionFormProps {
  onSubmit: (transaction: Omit<Transaction, "id">) => void;
  onCancel: () => void;
}

export default function AddTransactionForm({
  onSubmit,
  onCancel,
}: AddTransactionFormProps) {
  const { t } = useTranslation();
  const userSetting = useSelector((state: RootState) => state.userSettings);
  const userCurrency = (userSetting?.settings?.currency || "USD") as Currency;
  const currencySymbol = currencyService.getSymbol(userCurrency);

  const [transactionType, setTransactionType] = useState<"income" | "expense">(
    "expense",
  );
  const [formData, setFormData] = useState<Omit<Transaction, "id">>({
    date: new Date(),
    category: "Other",
    description: "",
    amount: undefined as unknown as number,
    currency: userCurrency,
    status: "Pending",
  });

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>,
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: name === "amount" ? Math.abs(parseFloat(value) || 0) : value,
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const absAmount = Math.abs(formData.amount);

    if (Number.isNaN(absAmount) || absAmount === 0) {
      errorToast(t("transactions.zeroAmountMsg"), 3000, "invalid-amount");
      return;
    }

    if (
      !currencyService.validateAmount(absAmount, formData.currency as Currency)
    ) {
      errorToast(
        t("transactions.invalidCurrencyAmount"),
        3000,
        "invalid-amount",
      );
      return;
    }

    // Apply sign: expense → negative, income → positive
    const signedAmount = transactionType === "expense" ? -absAmount : absAmount;

    onSubmit({
      ...formData,
      amount: currencyService.normalizeAmount(
        signedAmount,
        formData.currency as Currency,
      ),
      date: new Date(),
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {/* Income / Expense Toggle */}
      <div className="space-y-2">
        <Label>{t("transactions.type")}</Label>
        <div className="flex rounded-lg border border-slate-200 dark:border-slate-700 overflow-hidden">
          <button
            type="button"
            onClick={() => setTransactionType("expense")}
            className={`flex-1 px-4 py-2 text-sm font-medium transition-colors ${
              transactionType === "expense"
                ? "bg-red-500 text-white"
                : "bg-white text-slate-600 hover:bg-slate-50 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700"
            }`}
          >
            {t("transactions.expense")}
          </button>
          <button
            type="button"
            onClick={() => setTransactionType("income")}
            className={`flex-1 px-4 py-2 text-sm font-medium transition-colors ${
              transactionType === "income"
                ? "bg-green-500 text-white"
                : "bg-white text-slate-600 hover:bg-slate-50 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700"
            }`}
          >
            {t("transactions.income")}
          </button>
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="category">{t("transactions.category")}</Label>
        <select
          id="category"
          name="category"
          value={formData.category}
          onChange={handleChange}
          className="w-full rounded-md border border-slate-200 bg-white px-3 py-2 text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500 dark:border-slate-700 dark:bg-slate-800 dark:text-white"
          required
        >
          <option value="Other">{t("categories.other")}</option>
          {TRANSACTION_CATEGORIES.filter(
            (category) => category !== "All" && category !== "Todos",
          ).map((category) => (
            <option key={category} value={category}>
              {t(`categories.${category.toLowerCase()}`)}
            </option>
          ))}
        </select>
      </div>

      <div className="space-y-2">
        <Label htmlFor="description">{t("transactions.description")}</Label>
        <Input
          id="description"
          name="description"
          value={formData.description}
          onChange={handleChange}
          placeholder={t("transactions.enterDescription")}
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="amount">{t("transactions.amount")}</Label>
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
            {currencySymbol}
          </span>
          <Input
            id="amount"
            name="amount"
            type="number"
            step="0.01"
            min="0"
            value={formData.amount ?? ""}
            onChange={(e) => {
              const { value } = e.target;
              setFormData((prev) => ({
                ...prev,
                amount:
                  value === ""
                    ? (undefined as unknown as number)
                    : Math.abs(parseFloat(value) || 0),
              }));
            }}
            className="pl-7"
            placeholder={t("common.amountPlaceholder")}
            required
          />
        </div>
        <p className="text-xs text-slate-500 dark:text-slate-400">
          {t("transactions.amountHint")}
        </p>
      </div>

      <div className="space-y-2 grid">
        <Label htmlFor="status">{t("transactions.status")}</Label>
        <select
          id="status"
          name="status"
          value={formData.status}
          onChange={handleChange}
          className="w-full rounded-md border border-slate-200 bg-white px-3 py-2 text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500 dark:border-slate-700 dark:bg-slate-800 dark:text-white"
          required
        >
          <option value="Pending">{t("transactions.statusPending")}</option>
          <option value="Completed">{t("transactions.statusCompleted")}</option>
          <option value="Cancelled">{t("transactions.statusCancelled")}</option>
        </select>
      </div>

      <div className="mt-6 flex justify-end gap-2">
        <Button type="button" variant="outline" onClick={onCancel}>
          {t("common.cancel")}
        </Button>
        <Button type="submit">{t("transactions.addTransaction")}</Button>
      </div>
    </form>
  );
}

import { HttpTransactionRepository } from "@adapters/http/transaction.repository";
import { Transaction } from "@domain/dashboard/transactions/transaction.entity";
import { Modal } from "@presentation/components/modal/modal";
import { Button } from "@presentation/components/ui/button";
import { successToast, errorToast } from "@presentation/utils/toast";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Pencil } from "lucide-react";
import { useState } from "react";
import { useTranslation } from "react-i18next";
import { TransactionForm } from "./transaction-form";

interface EditTransactionButtonProps {
  transaction: Transaction;
  variant?:
    | "default"
    | "outline"
    | "secondary"
    | "ghost"
    | "link"
    | "destructive";
  children?: React.ReactNode;
}

export function EditTransaction({
  transaction,
  variant = "ghost",
  children,
}: EditTransactionButtonProps) {
  const { t } = useTranslation();
  const [isOpen, setIsOpen] = useState(false);

  const queryClient = useQueryClient();

  const { mutate: updateTransaction } = useMutation({
    mutationKey: ["add-transaction"],
    mutationFn: HttpTransactionRepository.updateTransaction,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    onSuccess: (data: any) => {
      successToast(data.message, 3000, "transaction-create");
      setIsOpen(false);
      queryClient.invalidateQueries({ queryKey: ["transactions"] });
      queryClient.invalidateQueries({ queryKey: ["dashboard"] });
    },
    onError: (error) => {
      errorToast(error.message, 3000, "transaction-create");
    },
  });

  const handleUpdateTransaction = (
    updatedTransaction: Partial<Transaction>,
  ) => {
    if (updatedTransaction.id === undefined) {
      errorToast(t("transactions.idRequired"), 3000, "transaction-update");
      return;
    }
    updateTransaction({
      dto: {
        ...updatedTransaction,
        amount: Number(updatedTransaction.amount),
      },
    });
    setIsOpen(false);
    queryClient.invalidateQueries({ queryKey: ["transactions"] });
  };

  return (
    <>
      <Button
        onClick={() => setIsOpen(true)}
        variant={variant}
        size="icon"
        className="h-8 w-8 p-0"
      >
        {children || <Pencil className="h-4 w-4" />}
      </Button>

      <Modal
        isOpen={isOpen}
        onClose={() => setIsOpen(false)}
        title={t("transactions.editTransaction")}
      >
        <TransactionForm
          transaction={transaction}
          onSubmit={handleUpdateTransaction}
          onCancel={() => setIsOpen(false)}
        />
      </Modal>
    </>
  );
}

import {
  TRANSACTION_CATEGORIES,
  TRANSACTION_STATUSES,
} from "@domain/dashboard/transactions/transaction.entity";
import { Modal } from "@presentation/components/modal/modal";
import { Button } from "@presentation/components/ui/button";
import { Input } from "@presentation/components/ui/input";
import { Label } from "@presentation/components/ui/label";
import { warningToast } from "@presentation/utils/toast";
import { useState } from "react";
import { useTranslation } from "react-i18next";

// Tipos más estrictos
type Category = (typeof TRANSACTION_CATEGORIES)[number];
type Status = (typeof TRANSACTION_STATUSES)[number];

export interface FilterCriteria {
  dateFrom: string;
  dateTo: string;
  categories: Category[];
  minAmount: number | null;
  maxAmount: number | null;
  statuses: Status[];
}

interface FilterModalProps {
  isOpen: boolean;
  onClose: () => void;
  onApplyFilters: (filters: FilterCriteria) => void;
  currentFilters: FilterCriteria;
}

// Helper para manejar selección de opciones
const handleOptionSelection = <T extends string>(
  currentOptions: T[],
  selectedOption: T,
  allOption: T,
): T[] => {
  if (selectedOption === allOption) {
    return currentOptions.includes(allOption) ? [] : [allOption];
  }

  return currentOptions.includes(selectedOption)
    ? currentOptions.filter((option) => option !== selectedOption)
    : [
        ...currentOptions.filter((option) => option !== allOption),
        selectedOption,
      ];
};

export function FilterModal({
  isOpen,
  onClose,
  onApplyFilters,
  currentFilters,
}: FilterModalProps) {
  const { t } = useTranslation();
  const [filters, setFilters] = useState<FilterCriteria>(currentFilters);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
  };

  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    const numericValue = value === "" ? null : parseFloat(value);
    setFilters((prev) => ({ ...prev, [name]: numericValue }));
  };

  const handleCategoryChange = (category: Category) => {
    setFilters((prev) => ({
      ...prev,
      categories: handleOptionSelection(prev.categories, category, "All"),
    }));
  };

  const handleStatusChange = (status: Status) => {
    setFilters((prev) => ({
      ...prev,
      statuses: handleOptionSelection(prev.statuses, status, "All"),
    }));
  };

  const validateFilters = (): boolean => {
    if (
      filters.dateFrom &&
      filters.dateTo &&
      filters.dateFrom > filters.dateTo
    ) {
      warningToast(t("common.warningDateFromBeforeTo"), 3000, "from-date");
      return false;
    }

    if (
      filters.minAmount !== null &&
      filters.maxAmount !== null &&
      filters.minAmount > filters.maxAmount
    ) {
      warningToast(
        t("common.warningMinAmountLessThanMax"),
        3000,
        "amount-range",
      );
      return false;
    }

    return true;
  };

  const handleApply = () => {
    if (!validateFilters()) return;

    onApplyFilters(filters);
    onClose();
  };

  const handleReset = () => {
    const resetFilters: FilterCriteria = {
      dateFrom: "",
      dateTo: "",
      categories: ["All"],
      minAmount: null,
      maxAmount: null,
      statuses: ["All"],
    };
    setFilters(resetFilters);
    onApplyFilters(resetFilters);
    onClose();
  };

  // Componente reutilizable para botones de opción
  const OptionButton = <T extends string>({
    option,
    selectedOptions,
    onClick,
    label,
  }: {
    option: T;
    selectedOptions: T[];
    onClick: (option: T) => void;
    label: string;
  }) => (
    <button
      type="button"
      onClick={() => onClick(option)}
      className={`rounded-full px-3 py-1 text-xs font-medium ${
        selectedOptions.includes(option)
          ? "bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200"
          : "bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-200"
      }`}
      aria-pressed={selectedOptions.includes(option)}
      aria-label={`${t("common.filterBy")} ${label}`}
    >
      {label}
    </button>
  );

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={t("common.applyFilters")}>
      <div className="space-y-4">
        {/* Sección de fechas */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label htmlFor="dateFrom">{t("common.fromDate")}</Label>
            <Input
              id="dateFrom"
              name="dateFrom"
              type="date"
              value={filters.dateFrom}
              onChange={handleChange}
              className="w-full"
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="dateTo">{t("common.toDate")}</Label>
            <Input
              id="dateTo"
              name="dateTo"
              type="date"
              value={filters.dateTo}
              onChange={handleChange}
              className="w-full"
            />
          </div>
        </div>

        {/* Sección de categorías */}
        <div className="space-y-2">
          <Label>{t("transactions.category")}</Label>
          <div className="flex flex-wrap gap-2">
            {TRANSACTION_CATEGORIES.map((category) => (
              <OptionButton
                key={category}
                option={category}
                selectedOptions={filters.categories}
                onClick={handleCategoryChange}
                label={t(`categories.${category.toLowerCase()}`)}
              />
            ))}
          </div>
        </div>

        {/* Sección de montos */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label htmlFor="minAmount">{t("common.minAmount")}</Label>
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
                $
              </span>
              <Input
                id="minAmount"
                name="minAmount"
                type="number"
                step="0.01"
                value={filters.minAmount ?? ""}
                onChange={handleAmountChange}
                className="pl-7"
                placeholder={t("common.amountPlaceholder")}
              />
            </div>
          </div>
          <div className="space-y-2">
            <Label htmlFor="maxAmount">{t("common.maxAmount")}</Label>
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
                $
              </span>
              <Input
                id="maxAmount"
                name="maxAmount"
                type="number"
                step="0.01"
                value={filters.maxAmount ?? ""}
                onChange={handleAmountChange}
                className="pl-7"
                placeholder={t("common.amountPlaceholder")}
                min="0"
              />
            </div>
          </div>
        </div>

        {/* Sección de estados */}
        <div className="space-y-2">
          <Label>{t("transactions.status")}</Label>
          <div className="flex flex-wrap gap-2">
            {TRANSACTION_STATUSES.map((status) => (
              <OptionButton
                key={status}
                option={status}
                selectedOptions={filters.statuses}
                onClick={handleStatusChange}
                label={
                  status === "All"
                    ? t("statuses.all")
                    : t(`transactions.status${status}`)
                }
              />
            ))}
          </div>
        </div>

        {/* Acciones */}
        <div className="mt-6 flex justify-end gap-2">
          <Button type="button" variant="outline" onClick={handleReset}>
            {t("common.reset")}
          </Button>
          <Button type="button" onClick={handleApply}>
            {t("common.applyFilters")}
          </Button>
        </div>
      </div>
    </Modal>
  );
}

