        ) : (
          <Skeleton key={i} className={`h-4 ${col.width} shrink-0`} />
        ),
      )}
      {hasActions && (
        <div className="flex gap-2 ml-auto shrink-0">
          <Skeleton className="h-8 w-8 rounded-md" />
          <Skeleton className="h-8 w-8 rounded-md" />
        </div>
      )}
    </div>
