          savings={savings}
        />
      )}

      {/* Categories Tab */}
      {activeTab === "categories" && (
        <CategoryTab
          insights={insights}
          weeklyTrend={weeklyTrend}
          categories={categories}
          isLoadingInsights={isLoadingInsights}
          totalExpenses={totalExpenses}
        />
      )}

      {/* Trends Tab */}
      {activeTab === "trends" && (
        <TrendsTab
          insights={insights}
          weeklyTrend={weeklyTrend}
          overview={overview}
          isLoadingTrend={isLoadingTrend}
