import { useSelector } from "react-redux";
import ProfileLoading from "./loading-profile";

export default function Profile() {
  const { t } = useTranslation();
  const user = useSelector((state: RootState) => state.auth.user);
  const [activeTab, setActiveTab] = useState("personal-info");

  if (!user) {
    return <ProfileLoading />;
  }

  return (
    <div className="space-y-6">
      <PageHeader
        title={t("profile.title")}
        description={t("profile.description")}
      />

      <Tabs
        defaultValue="personal-info"
        value={activeTab}
        onValueChange={setActiveTab}
        className="space-y-4"
      >
        <TabsList className="grid w-full grid-cols-4 lg:w-auto bg-accent/35 dark:bg-accent/30">
          <TabsTrigger
            className="text-primary dark:text-neutral"
            value="personal-info"
          >
            {t("profile.personalInfo")}
          </TabsTrigger>
          <TabsTrigger
            className="text-primary dark:text-neutral"
            value="security"
          >
            {t("profile.security")}
          </TabsTrigger>
          <TabsTrigger
            className="text-primary dark:text-neutral"
            value="notifications"
          >
            {t("profile.notifications")}
          </TabsTrigger>
          <TabsTrigger
            className="text-primary dark:text-neutral"
            value="account"
          >
            {t("profile.account")}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="personal-info" className="space-y-4">
          <PersonalInfoForm />
        </TabsContent>

        <TabsContent value="security" className="space-y-4">
          <SecuritySettings />
        </TabsContent>

        <TabsContent value="notifications" className="space-y-4">
          <NotificationSettings />
        </TabsContent>

        <TabsContent value="account" className="space-y-4">
          <AccountSettings />
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useUserList } from "@adapters/query/userQuery";
import { Link } from "react-router";

export default function UserList() {
  const { data: users } = useUserList();

  return (
    <div>
      <h1>User List</h1>
      <ul>
        {users &&
          users.map((user) => (
            <li key={user.id}>
              <Link to={`/app/user/${user.id}`}>{user.name}</Link>
            </li>
          ))}
      </ul>
    </div>
  );
}

import { RootState } from "@adapters/store/rootStore";
import MainLayout from "@presentation/layouts/main";
import { RoutePaths } from "@presentation/utils/routes";
import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Navigate, useLocation } from "react-router";

/**
 * A component that acts as a protected route, ensuring that only authenticated users
 * can access certain parts of the application. It checks the authentication status
 * and user information from the Redux store. If the user is not authenticated and
 * the loading state is false, it redirects to the login page. Otherwise, it renders
 * the main layout of the application.
 *
 * @returns {JSX.Element} - The main layout if authenticated, or a redirect to the login page.
 */
const ProtectedRoute = () => {
  const isAuthenticated = useSelector(
    (state: RootState) => state.auth.isAuthenticated,
  );
  const user = useSelector((state: RootState) => state.auth.user);
  const [loading, setLoading] = useState(true);
  const token = localStorage.getItem("accessToken");
  const location = useLocation();

  useEffect(() => {
    const timeout = setTimeout(() => {
      setLoading(false);
    }, 1000);

    return () => clearTimeout(timeout);
  }, []);

  if (!location.pathname.includes(RoutePaths.Auth || RoutePaths.App)) {
    return <MainLayout />;
  }
  if (token) {
    console.debug("No token found, redirecting to login");
    return <Navigate to={RoutePaths.Auth + "/" + RoutePaths.Login} replace />;
  }

  if (!isAuthenticated && !user && !loading) {
    return <Navigate to={RoutePaths.Auth + "/" + RoutePaths.Login} replace />;
  }

  return <MainLayout />;
};

export default ProtectedRoute;

