import AuthLayout from "@presentation/layouts/auth";
import ForgotPasswordConfirmationPage from "@presentation/pages/auth/confirmation";
import ForgotPasswordPage from "@presentation/pages/auth/forgot-password";
import LoginPage from "@presentation/pages/auth/login";
import ResetPasswordPage from "@presentation/pages/auth/reset-password";
import SignupPage from "@presentation/pages/auth/signup";
import ContactSalesPage from "@presentation/pages/contact/contact-sales-page";
import PrivacyPolicyPage from "@presentation/pages/contact/privacy-policy-page";
import TermsOfServicePage from "@presentation/pages/contact/terms-of-service-page";
import CTAPage from "@presentation/pages/cta";
import { lazy } from "react";
import { Route, Routes } from "react-router";
import ProfilePage from "@presentation/pages/user/profile";

import ProtectedRoute from "./protected-route";
import UserList from "@presentation/pages/user/userList";
import HowItWorksPage from "@presentation/pages/demo/how-it-works";
import NotFoundPage from "@presentation/pages/notFound";
const DashboardPage = lazy(
  () => import("@presentation/pages/dashboard/dashboardPage"),
);
import { RoutePaths } from "@presentation/utils/routes";
import LoadingPage from "@presentation/pages/loading";
import ReportsPage from "@presentation/pages/dashboard/reportsPage";
import TransactionsPage from "@presentation/pages/dashboard/transactionPage";
import IncomePage from "@presentation/pages/dashboard/incomePage";
import BudgetsPage from "@presentation/pages/dashboard/budgetsPage";
import { GoalsPage } from "@presentation/pages/dashboard/goalsPage";
import LandingLayout from "@presentation/layouts/landing";

const RouteConfig = () => {
  return (
    <Routes>
      {/* Rutas públicas */}
      <Route path={RoutePaths.Home} element={<CTAPage />} />
      <Route element={<LandingLayout />}>
        <Route path={RoutePaths.HowItWorks} element={<HowItWorksPage />} />
        <Route
          path={RoutePaths.PrivacyPolicy}
          element={<PrivacyPolicyPage />}
        />
        <Route
          path={RoutePaths.TersmsAndConditions}
          element={<TermsOfServicePage />}
        />
        <Route path={RoutePaths.ContactSales} element={<ContactSalesPage />} />
      </Route>
      <Route path={RoutePaths.Auth} element={<AuthLayout />}>
        <Route path={RoutePaths.Login} element={<LoginPage />} />
        <Route path={RoutePaths.Signup} element={<SignupPage />} />
        <Route
          path={RoutePaths.ForgotPassword}
          element={<ForgotPasswordPage />}
        />
        <Route
          path={RoutePaths.ForgotPasswordConfirmation}
          element={<ForgotPasswordConfirmationPage />}
        />
        <Route
          path={RoutePaths.ResetPassword}
          element={<ResetPasswordPage />}
        />
      </Route>
      {/* Rutas protegidas */}
      <Route path={RoutePaths.App} element={<ProtectedRoute />}>
        {/* dashboard section */}
        <Route
          path={RoutePaths.Dashboard}
          loader={LoadingPage}
          element={<DashboardPage />}
        />
        <Route path={RoutePaths.Transactions} element={<TransactionsPage />} />
        <Route path={RoutePaths.Income} element={<IncomePage />} />
        <Route path={RoutePaths.Goals} element={<GoalsPage />} />
        <Route path={RoutePaths.Budgets} element={<BudgetsPage />} />
        <Route path={RoutePaths.Reports} element={<ReportsPage />} />
        {/* user section */}
        <Route path={RoutePaths.Profile} element={<ProfilePage />} />
        <Route path={RoutePaths.UserList} element={<UserList />} />
        <Route path={RoutePaths.UserDetail} element={<ProfilePage />} />
      </Route>

      {/* Error page */}
      <Route path="*" element={<NotFoundPage />} />
    </Routes>
  );
};

export default RouteConfig;

import {
  AlertTriangle,
  Check,
  CheckCircle2,
  Info,
  X,
  XCircle,
} from "lucide-react";
import toast from "react-hot-toast";

interface CustomToastProps {
  message: string;
  type?: "warning" | "info" | "error" | "success";
  duration?: number;
  id?: string;
}

interface ConfirmToastOptions {
  onConfirm: () => void;
  labelCancel?: string;
  labelConfirm?: string;
}

const customToast = ({
  message,
  type = "info",
  duration = 5000,
}: CustomToastProps) => {
  const toastStyles = {
    warning: {
      bg: "bg-amber-50 dark:bg-amber-900/30",
      border: "border-amber-200 dark:border-amber-800",
      text: "text-amber-800 dark:text-amber-200",
      icon: (
        <AlertTriangle className="h-5 w-5 text-amber-500 dark:text-amber-400" />
      ),
    },
    info: {
      bg: "bg-blue-50 dark:bg-blue-900/30",
      border: "border-blue-200 dark:border-blue-800",
      text: "text-blue-800 dark:text-blue-200",
      icon: <Info className="h-5 w-5 text-blue-500 dark:text-blue-400" />,
    },
    error: {
      bg: "bg-red-50 dark:bg-red-900/30",
      border: "border-red-200 dark:border-red-800",
      text: "text-red-800 dark:text-red-200",
      icon: <XCircle className="h-5 w-5 text-red-500 dark:text-red-400" />,
    },
    success: {
      bg: "bg-green-50 dark:bg-green-900/30",
      border: "border-green-200 dark:border-green-800",
      text: "text-green-800 dark:text-green-200",
      icon: (
        <CheckCircle2 className="h-5 w-5 text-green-500 dark:text-green-400" />
      ),
    },
  };

  return toast.custom(
    (t) => (
      <div
        className={`${t.visible ? "animate-enter" : "animate-leave"}
          max-w-md w-full ${toastStyles[type].bg} ${toastStyles[type].border}
          shadow-lg rounded-lg pointer-events-auto flex items-center p-4 border
          transition-all duration-300`}
      >
        <div className="flex-shrink-0 mr-3">{toastStyles[type].icon}</div>
        <div className={`flex-1 text-sm ${toastStyles[type].text}`}>
          {message}
        </div>
        <button
          onClick={() => toast.dismiss(t.id)}
          className="ml-4 flex-shrink-0 rounded-md inline-flex text-slate-400 hover:text-slate-500 focus:outline-none"
        >
          <X className="h-5 w-5" />
        </button>
      </div>
    ),
    { duration },
  );
};

export const warningToast = (message: string, duration?: number, id?: string) =>
  customToast({ message, type: "warning", duration, id });

export const infoToast = (message: string, duration?: number, id?: string) =>
  customToast({ message, type: "info", duration, id });

export const errorToast = (message: string, duration?: number, id?: string) =>
  customToast({ message, type: "error", duration, id });

export const successToast = (message: string, duration?: number, id?: string) =>
  customToast({ message, type: "success", duration, id });

export const confirmToast = (
  message: string,
  options: ConfirmToastOptions,
  duration?: number,
) => {
  return toast.custom(
    (t) => (
      <div
        className={`${t.visible ? "animate-enter" : "animate-leave"}
          max-w-md w-full bg-card dark:bg-card dark:text-neutral
          shadow-lg rounded-lg pointer-events-auto flex flex-col items-center justify-between p-4 border
          transition-all duration-300`}
      >
        <div className="flex items-center">
          <div className="flex-shrink-0 mr-3">
            <AlertTriangle className="h-5 w-5 text-yellow-500 dark:text-yellow-400" />
          </div>
          <div className="flex-1 text-sm text-slate-400">{message}</div>
        </div>
        <div className="flex items-center space-x-2">
          <button
            onClick={() => toast.dismiss(t.id)}
            className="rounded-md px-3 py-2 text-sm font-medium text-slate-400 hover:text-slate-500 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-slate-500 dark:text-slate-300 dark:hover:text-slate-200 dark:focus-visible:ring-slate-400"
          >
            {options.labelCancel || "Cancel"}
          </button>
          <button
            onClick={() => {
              options.onConfirm();
              toast.dismiss(t.id);
            }}
            className="flex gap-4 rounded-md px-3 py-2 text-sm font-medium text-red-500 hover:text-red-600 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-red-500 dark:text-red-400 dark:hover:text-red-300 dark:focus-visible:ring-red-400"
          >
            {options.labelConfirm || "Accept"}
            <Check className="ml-1 h-4 w-4 inline-block" />
          </button>
        </div>
      </div>
    ),
    { duration },
  );
};
